insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2018-01-19','(Pedro)Conversación con Dª Mª Teresa Perales Bravo, abogada (927-627263. Móvil: 666467766 y Fax:927-626417. +++Se informa de que la situación esconocida por Fiscalía y que desde CTAEx se está haciendo su seguimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2018-01-19','(Pedro)Llamada de Anabel (Valoradora Dependencia Cáceres (22050). +++DEPENDENCIA GRADO I. Nos llegará la Resolcuión. +++La familia se quiere poner en contacto con nosotros. Además del teléfono de Saturnino y de su madre (que ya tenemos) nos da el siguiente:690671204. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Trato de ponerme en contacto con Francisco, hermano de Saturnino, pero no lo cogen y cortan la llamada. Llamo a Dª Isabel, pero no coge el teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ELIAS'and edp.apellido1='MACHIO'and apellido2='FLORIDO'),'2018-01-19','(Pedro)Conversación con Teresa, Médica de la Residencia San Francisco (924-021882): +++Elías sigue ingresado por un síndrome febril originado probablemte por la insuficiencia respiratoria, pero no tiene nuemonía. +++Sigue insistiendo en volver a su casa.PROPUESTA: ver la posibilidad de llevarlo a su pueblo a pasar el día (cuando mejore el tiempo) y volver por la tarde. Lo planteará a Petri (Directora). Por parte de la Comisión, si lo creen adecuado, no habrá problema para autorizarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-01-22','Iciar: Llama Mamen del centro Vida- Cáritas de Cáceres, 607 680 553, donde se encuentra José Manuel. Quiere comentar la situación pues J.M. está ocupando una plaza cuando tiene su palza reservada en el CRR de Mérida.ELla ya sabe que se debe a una medida terapeútica pero considera que está en una plaza que alguien podría necesitar sobre todo ahora que están en la campaña de frio. Comenta que la medida es hasta el día 31 de enero,como le ha informado Beatriz, y aunque JM tiene un hermano, este no quiere que vaya a su casa, además de que el piso de JM no tiene ni luz ni agua.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2018-01-22','Iciar: Llama Concha diciendo que necesita 100€ para coger un taxi e ingresar en el hospital pues se encuentra mal. Le comento que deería haber hablado con Gisela del CRR pero me dice que ya está en Badajoz. Hablo con Raquel del CRR y me comenta que Concha no necesita ese dinero, como la vez anterior le salió bien y consiguió el dinero de la Comisión ahora intenta hacer lo mismo. Si necesita ir al hospital puede llamar a una ambulancia si tan mal se siente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GENARO'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2018-01-22','DESPLAZAMIENTO El 22/01/2018. "Buenos días, comunico que Genaro... hoy va a desplazarse a Don Benito con un trabajador de la Asociación para visitar a su hrmano que se encuentra en el CAM de Don Benito. Un saludo."','2');
