insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BASILISO'and edp.apellido1='JIMENEZ'and apellido2='HERNANDEZ'),'2018-01-09','SALIDA Acude a la residencia solamente a la hora de las comidas, el resto del día está por el pueblo o en su propia casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='GARCIA'and apellido2='AMBROSIO'),'2018-01-09','SALIDA Sale todos los días al pueblo, solo o con algún compañero. El día 17/11/2017 acude a Plasencia a Consulta de Salud Mental. El día 02/10/2017 participa en la excursión a la Feria de Ganado de Zafra. Acude, también, el día 02/12/2017 a las Jornadas por el día de la Discapacidad en Coria. Y el día 27/12/2017 a la Fiesta de Navidad de la Casa de la Misericordia de Alcuéscar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCOS'and edp.apellido1='GARRIDO'and apellido2='PEREZ'),'2018-01-09','SALIDA Todos los días va de paseo con los compañeros y participa en salidas ocasionales por el pueblo. Participa, el día 02/12/2017, en las Jornadas por el día de la Discapacidad en Coria. Acude, el día 27/12/2017, a la Fiesta de Navidad de la Casa de la Misericordia de Alcuéscar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2017-01-09','SALIDA Sale esporádicamente por el pueblo y a dar algún paseo por los alrededores con los compañeros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2017-11-10','SALIDA El 10/11/2017 plantea nuevamente, la residente, la posibilidad de realizar un viaje a Don Benito con el objeto de visitar a Juan Martín Isidoro. Refiere que es su pareja sentimental desde abril de 2017. Según consta en el registro de visitas la ha venido a visitar e numerosas Ocasiones.**************************************************En la actualidad, es Isabel Debón quien quiere viajar a Don Benito del 15 al 19 de noviembre y pernoctar en el domicilio de Juan Martín Isidoro. Para ello, realizaría los desplazamientos en el coche particular de su pareja. Se trata de un vehículo que no es necesario disponer de carnet de conducir por lo que la residente llevará una silla de ruedas manual prestada en Terapia Ocupacional.**************Valoración: Desde el inicio de la relación Juan Martín Isidoro ha mostrado buena disposición el Centro, identificándose siempre que ha venido e incluso facilitando, por su propia iniciativa una copia de su DNI a este departamento. Visto el caso en reunión de equipo técnico, comentan haber tratado el tema con la residente. Incluso que les ha presentado a su pareja. No refieren motivos de alarma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2017-11-27','SALIDA El 27/11/2017 plantea nuevamente, la residente, la posibilidad de realizar un viaje a Don Benito con el objeto de pasar las navidades con Juan Martín Isidoro y familia, del 23/12/2017 al 02/01/2018. Su pareja sentiental desde abril de 2017. Para ello, realizaría los desplazamientos en el coche particular de su pareja. Se trata de un vehículo que no es necesario disponer de carnet de conducir por lo que la residente llevará una silla de ruedas manual prestada en Terapia Ocupacional.****************************Valoración: Desde el inicio de la relación Juan Martín Isidoro ha mostrado buena disposición con el Centro, identificándose siempre que ha venido e, incluso, facilitando, por propia iniciativa, una copia de su DNI a este Departamento. Visto el caso en reunión de equipo técnico, comentan haber tratado el tema con la residente, incluso que les ha presentado a su pareja. No refieren motivos de alarma.*****************************************************Maribel Debón no regresará hasta el 07/01/2018.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2018-01-22','Iciar: HAblo con Mariola de Salud Mental 41610- Le comento la llamada de RAmón del viernes pasado pidiendo 80€ para ir a visitar a su hermana a VAlencia. Dice que el pasado jueves estuvo con Eugenia y Silvia visitando A Ramón. Estaba bastante alterado aunque se dejó poner el inyectable. La familia intenta dentro de sus posibilidades mantener la casa limpia pero el único que no colabora es Ramón, su habitación está sucia y él es quien recoge enseres de la calle y los pone en la habitación de la madre, no colabora en nada.Van a mandar informe a la Comisión. El próximo jueves volverá a ir a visitarle con Eugenia y Silvia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2018-01-22','iciar. Llaman de Ayto de Alburquerque para decir que Isidoro está ingresado. Llamo al T/S del Hospital Infanta Juanjo, me informan que sigue en observación. No saben si le darán el alta o pasará a planta. Nos llama','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2017-10-10','SALIDA El 10/10/2017. Excursión a la Ruta de los Molinos de Arroyomolinos de Montánchez. Salida a las 14:00 Hs, regreso a las 19:30 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2017-10-19','SALIDA El 19/10/2017. Excursión a Badajoz. Salida 10:30 Hs., regreso 19:00 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2017-12-14','SALIDA El 14/12/2017. Viaje a Cáceres. Exposición de fotografía. Salida a las 10:00 Hs., regreso a las 14:30 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='BARQUERO'and apellido2='MARTIN'),'2018-01-22','TRASLADO El 22/01/2018. "...ingresado en este Centro y tutelado por esa Comisión, será trasladado al HOSPITAL DE MÉRIDA (URGENCIAS)..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2018-01-23','Iciar: Hablamos con el Juzgado de Villanueva nos confirman que a la comparecencia por el tema de abusos no hace falta que vaya la Comisión ni tampoco Yolanda. Llamo a Aprosuba 9 para informarles. Maribel nos dice que Yolanda recibió el alta el viernes del Hospital y ha salido más desajustada que ingresó. Han enviado la solicitud ala UDAC de Plasencia pero se temen no van a aceptarla pues debido a falta de perfiles profesionales, psicólogos y terapeutas, no están admitiendo a ningún nuevo paciente. Quedamos en hablar sobre cómo termina el tema del juicio por abusos.','1');
